proof fn phi_2_scheduled_deletion_timestamp_redundant(vrs: VReplicaSetView, controller_id: int, s: ClusterState)
    requires
        s.scheduled_reconciles(controller_id).contains_key(vrs.object_ref()),
        vrs_in_schedule_does_not_have_deletion_timestamp(vrs, controller_id)(s),
    ensures
        ({
            let obj = s.scheduled_reconciles(controller_id)[vrs.object_ref()];
            obj.metadata.deletion_timestamp is None
            && VReplicaSetView::unmarshal(obj).unwrap().metadata().deletion_timestamp is None
            && (VReplicaSetView::unmarshal(obj) is Ok ==> VReplicaSetView::unmarshal(obj)->Ok_0.metadata().deletion_timestamp == obj.metadata.deletion_timestamp)
        }),
{
}

proof fn phi_4_reconcile_spec_uid_no_status_check(controller_id: int, vrs: VReplicaSetView, s: ClusterState)
    requires
        s.ongoing_reconciles(controller_id).contains_key(vrs.object_ref()),
        Cluster::the_object_in_reconcile_has_spec_and_uid_as(controller_id, vrs)(s),
    ensures
        ({
            let cr = s.ongoing_reconciles(controller_id)[vrs.object_ref()].triggering_cr;
            cr.metadata.uid == vrs.metadata().uid
            && VReplicaSetView::unmarshal(cr)->Ok_0.spec() == vrs.spec()
        }),
